  'CBSE, board exams, and percentage culture — what IB looks like from a family inside that world.',
  '[
    {"author":"Kumar, K.","year":1991,"title":"Political Agenda of Education: A Study of Colonialist and Nationalist Ideas","publisher":"Sage Publications"},
    {"author":"Verma, S., Sharma, D., & Larson, R. W.","year":2002,"title":"School stress in India: Effects on time and daily emotions","journal":"Applied Developmental Science","doi":"10.1207/S1532480XADS0604_11"},
    {"author":"Bray, M.","year":2009,"title":"Confronting the Shadow Education System: What Government Policies for What Private Tutoring?","publisher":"UNESCO International Institute for Educational Planning"},
    {"author":"Sujatha, K.","year":2014,"title":"Private tuition in India: Patterns and policy concerns","journal":"Prospects","doi":"10.1007/s11125-014-9307-9"}
  ]'::jsonb,
  '{"pdi":77,"idv":48,"mas":56,"uai":40,"lto":51,"ivr":26}'::jsonb,
