-- ── DIMENSIONS ────────────────────────────────────────────────────────────────

INSERT INTO pd_dimensions (module_id, dimension_number, title, research_status, content) VALUES

-- ── D1: Learning Philosophy ───────────────────────────────────────────────────
('india-001', 1, 'Performance as Virtue: Two Models of What Learning Is', 'fully_sourced',
  $${"summary":"In international classrooms, learning is framed around curiosity, inquiry, and the development of understanding over time. In the CBSE-shaped reality most Indian students come from, learning is framed around performance optimization — how to secure the highest possible marks in the least possible time. These are not minor pedagogical differences; they are rival definitions of what it means to be a serious student. A teacher who cannot read the second frame will misinterpret nearly every signal she receives from high-achieving Indian students and families.","sections":[{"heading":"The CBSE Performance Frame","items":["CBSE assessment architecture is predominantly structured-recall: model answers exist, partial marks are a real system, and exam technique is a learnable skill distinct from subject understanding.","The highest-performing students learn to optimize for marks rather than for understanding — these are different skills, and students know it. Efficient CBSE exam technique requires identifying the expected format, writing to that format precisely, and avoiding the risk of creative deviation.","'Is this in the exam?' is not cynicism; it is a rational question inside a system designed entirely around terminal external examinations. The student asking it is operating exactly as the system trained them to.","Kumar (1991) traces this examination orientation to colonial-era educational policy: the British designed Indian schooling around administrative selection rather than human development, and that architecture persists in the CBSE marking culture today."]},{"heading":"Marks as Identity and Social Currency","items":["In Indian middle-class culture, academic marks are not merely performance data — they are a form of social identity communicated between families, in community settings, and across generations.","'95% means nothing if someone else in class scored 97%' is a sentence teachers hear literally. The competitive frame is not a parent's neurosis; it is a community-level comparison system in which the child's marks represent the family's educational capital.","Verma, Sharma & Larson (2002) found that Indian secondary students reported significantly higher academic stress than comparison groups in multiple cross-national studies, driven primarily by examination performance expectations and family-comparative pressure.","Students who have received high marks throughout CBSE schooling arrive in IB carrying an identity as 'toppers' — the top-ranked students. When IB assessment does not produce a rank, these students may initially read the absence of ranking as an absence of rigorous assessment."]},{"heading":"What This Means for IB and International Teachers","items":["The student who takes extremely detailed notes may not be curious — they may be risk-managing against the possibility of an unexpected assessment format.","The student who asks 'how many marks is this worth?' is operating normally within a system that taught them to allocate effort proportionally to marks value. This is expertise, not laziness.","Inquiry-based tasks feel disproportionately risky to students whose expertise is optimizing for structured marking schemes. The open-ended question is not harder — it is in a different game entirely, one they have not been trained to play.","The interpretive move: the student who appears passive or reluctant in inquiry is often very capable and is simply waiting to understand the new rules. Patience and explicit explanation of the assessment format typically unlocks engagement quickly."]}],"citations":[{"author":"Kumar, K.","year":1991,"title":"Political Agenda of Education: A Study of Colonialist and Nationalist Ideas","publisher":"Sage Publications"},{"author":"Verma, S., Sharma, D., & Larson, R. W.","year":2002,"title":"School stress in India: Effects on time and daily emotions","journal":"Applied Developmental Science","doi":"10.1207/S1532480XADS0604_11"}]}$$::jsonb),

-- ── D2: Parent Communication ──────────────────────────────────────────────────
('india-001', 2, 'The High-Investment Parent: Results, Relationship, and the WhatsApp Economy', 'fully_sourced',
  $${"summary":"International teachers often describe Indian parents as 'very involved' and sometimes 'demanding.' The more useful frame is: Indian parents at international schools are operating under a dual mandate. They have chosen an international school — often at considerable financial sacrifice — precisely because they believe it will optimize their child's long-term outcomes. They simultaneously carry CBSE-shaped expectations about what appropriate parental involvement looks like: close monitoring of marks, regular access to teachers, and a clear understanding of where their child ranks. The teacher who understands this is better positioned to turn an anxious parent into a genuine ally.","sections":[{"heading":"The Investment Calculus","items":["Families who have chosen an international school — particularly those paying premium fees in cities like Mumbai, Delhi, or Bangalore — have made a financial and social bet on the international credential.","For first-generation international-school families, this investment is especially visible: they have departed from the CBSE mainstream, often against the advice of their extended family, because they believe the international pathway is worth it.","Parents who ask frequently about marks or progress are often monitoring the return on this investment. Their persistence is not distrust of the teacher; it is a rational response to having made a high-stakes educational decision that their community will evaluate based on the child's outcomes.","The interpretive move: when a parent pushes for marks data before a meeting has formally started, recognize this as information-seeking by a highly invested stakeholder, not as aggressive behaviour."]},{"heading":"WhatsApp Groups and the Parent Information Economy","items":["WhatsApp parent groups in Indian school contexts are high-traffic, high-anxiety environments. Partial information — a test announced but grade not yet returned, a project with unclear rubric — spreads faster than official communication and generates disproportionate alarm.","Within these groups, parent interpretation of teacher behaviour circulates at speed. A teacher who does not acknowledge a test result within the expected timeframe may have a rumour about her assessment standards circulating before she is aware the conversation has started.","Sujatha (2014) notes that the coaching and tuition industry amplifies this communication pattern: parents compare school performance against coaching benchmarks in real time, and teachers are implicitly evaluated against coaching-sector standards.","Practical response: predictable communication schedules reduce WhatsApp noise more than any individual message does. If parents know that marks will be posted by Friday of the week following assessment, they will wait until Friday."]},{"heading":"The Parent-Teacher Meeting (PTM) Conversation","items":["PTM culture in Indian schooling expects a specific sequence: a report on recent marks, an implicit comparison with classmates (even when not made explicit), and a concrete plan for improvement before the next exam period.","A PTM that focuses on learning dispositions, inquiry skills, or collaborative behaviour without addressing marks data often leaves Indian parents feeling that their central question was evaded — not answered.","The teacher who begins with learning observations and never surfaces performance data will typically face a direct question about marks within the first three minutes. Planning for this is not capitulation to the marks culture; it is effective communication strategy.","The productive PTM format: acknowledge the marks picture first (briefly and accurately), then pivot to the learning story that explains the marks picture. Parents who feel heard on marks are significantly more open to the inquiry/IB frame that follows."]}],"citations":[{"author":"Verma, S., Sharma, D., & Larson, R. W.","year":2002,"title":"School stress in India: Effects on time and daily emotions","journal":"Applied Developmental Science","doi":"10.1207/S1532480XADS0604_11"},{"author":"Sujatha, K.","year":2014,"title":"Private tuition in India: Patterns and policy concerns","journal":"Prospects","doi":"10.1007/s11125-014-9307-9"}]}$$::jsonb),

-- ── D3: Institutional Context ─────────────────────────────────────────────────
('india-001', 3, 'The Shadow Curriculum: Coaching, Tutoring, and the Parallel System', 'fully_sourced',
  $${"summary":"For most Indian families, a coaching class or private tutor is not a sign of academic failure — it is normative, expected, and considered more rigorous than the school itself for outcomes that matter. The coaching ecosystem operates in parallel to school instruction, directly shapes what students know and how they think about learning, and is frequently the primary academic system in a family's life. A foreign teacher who treats tutoring as supplementary misreads the situation entirely.","sections":[{"heading":"How the Coaching System Works","items":["India's private tutoring market — estimated at USD 40+ billion and growing — operates at every level from primary through university entrance. For secondary students targeting JEE (engineering) or NEET (medicine), coaching is not optional; it is the pathway.","Major coaching institutes — FIITJEE, Allen, Aakash, Resonance, Narayana — run curricula that begin in Grade 8 or earlier, are more structured and outcome-focused than most school instruction, and issue their own assessments, rankings, and mock exams.","Students at international schools serving Indian families frequently attend coaching two to four hours per day after school, in addition to full school days. Their primary academic loyalty and most intense learning effort is directed at the coaching syllabus.","Bray (2009) identifies the shadow education system as a global phenomenon but notes that India represents one of its most institutionally developed forms: the coaching sector has its own pedagogy, its own certification of teachers, and its own theory of what rigorous learning looks like."]},{"heading":"When School and Coaching Conflict","items":["If the coaching teacher has taught a concept using a specific method, and the school teacher teaches it differently, students experience cognitive dissonance — and will typically default to the coaching method in high-stakes assessments.","This is not defiance; it is rational risk management. The coaching method has been tested and marked; the school method is unfamiliar under examination conditions.","A student who says 'my tutor taught me it differently' is offering you legitimate information about their actual learning architecture, not questioning your authority.","The most counterproductive response is to insist the student abandon the coaching method entirely. The most productive response is to explain what your method adds — what the coaching method does not cover — and let the student integrate both."]},{"heading":"JEE, NEET, and the Long-Term Pressure Architecture","items":["The Joint Entrance Examination (JEE) for engineering and National Eligibility cum Entrance Test (NEET) for medicine are among the most competitive examinations in the world: approximately 1.5 million students sit JEE each year for around 12,000 seats at the Indian Institutes of Technology.","Even students at international schools who do not intend to sit JEE or NEET are surrounded by peers and family members for whom these examinations are the entire purpose of secondary schooling. The pressure culture permeates even classrooms where IB or AP is the actual credential.","Parents who ask whether your class will 'help with JEE' are often not asking whether you will teach JEE content — they are asking whether studying in your class will make their child academically stronger and more competitive. The question deserves a substantive answer, not a dismissal.","Practical implication: knowing whether your students are in JEE/NEET coaching tracks allows you to understand their true cognitive load and time pressure. A student who appears disengaged at 8 AM may have finished a coaching session at 10 PM the previous night."]}],"citations":[{"author":"Bray, M.","year":2009,"title":"Confronting the Shadow Education System: What Government Policies for What Private Tutoring?","publisher":"UNESCO International Institute for Educational Planning"},{"author":"Sujatha, K.","year":2014,"title":"Private tuition in India: Patterns and policy concerns","journal":"Prospects","doi":"10.1007/s11125-014-9307-9"}]}$$::jsonb),

-- ── D4: Ethical Leadership ────────────────────────────────────────────────────
('india-001', 4, 'Ranking, Favoritism, and Classroom Equity', 'partial',
  $${"summary":"Indian classroom culture has historically normalized practices that international teaching ethics identify as harmful: public ranking of students by marks, differential treatment of 'toppers' (top-ranked students), and the visible stratification of students by academic performance. A foreign teacher in an international school is unlikely to practice these things — but will encounter their residual effects in student behavior, family expectations, and peer dynamics. Navigating this requires neither wholesale condemnation of Indian schooling culture nor naive acceptance of practices that undermine equity.","sections":[{"heading":"The Topper System","items":["In CBSE schools, the highest-ranked student is publicly celebrated: names on notice boards, announcements at assembly, differential teacher attention and resource access.","'Topper' is a social role, not just an academic label: toppers are consulted by peers for notes, favored in teacher interactions, and sometimes given differential access to teacher time or teaching materials.","Students who have been toppers in CBSE settings arrive in international schools expecting similar recognition. When IB assessment does not produce a public rank, these students sometimes interpret the absence of ranking as an institutional failure to acknowledge their achievement.","The ethical risk for foreign teachers: replicating implicit topper dynamics by consistently calling on high-performers, using their work as exemplars without transparency, or signaling differential confidence in their academic futures."]},{"heading":"Comparison as Motivation — and Its Damage","items":["'Rahul's sister got 98% — why did you only get 85%?' is a motivational technique in Indian middle-class family culture, not a cruelty. Sibling, cousin, and community comparison is normalized because academic marks are semi-public social information.","Between-family comparison in community settings — at temples, at parties, in apartment building groups — means that many students know their classmates' marks, even when teachers have not published them. Information about assessments travels through parent networks before grades are formally returned.","The damage: students who have repeatedly lost comparison conversations develop a settled identity as 'not the smart one' that is resistant to IB assessment evidence showing otherwise. Rebuilding this identity takes explicit, sustained, and specific affirmation — not generic encouragement.","The interpretive move for teachers: a student who reflexively self-deprecates about their academic ability ('I'm not good at Maths') may be accurately reporting years of comparison feedback, not fishing for reassurance. Treating it as a cognitive pattern to be explicitly changed — not just reassured — is more effective."]},{"heading":"Class, Aspiration, and Invisible Hierarchies","items":["At elite international schools in India, caste rarely surfaces explicitly in classroom interactions, but class and aspiration pressure operate as proxies for the same social stratification.","Students from wealthier, more established families may carry quiet social authority that shapes group dynamics, peer consultation patterns, and whose ideas are taken seriously in collaborative tasks.","Foreign teachers who are unfamiliar with Indian social stratification often misread these dynamics as personality differences rather than as the social hierarchy they represent.","Practical implication: deliberate grouping strategies, visible equal treatment, and explicit norms around idea ownership in collaborative work are not just good IB pedagogy — they are equity interventions in a context where hierarchy is the expected norm."]}],"citations":[{"author":"Kumar, K.","year":1991,"title":"Political Agenda of Education: A Study of Colonialist and Nationalist Ideas","publisher":"Sage Publications"},{"author":"Verma, S., Sharma, D., & Larson, R. W.","year":2002,"title":"School stress in India: Effects on time and daily emotions","journal":"Applied Developmental Science","doi":"10.1207/S1532480XADS0604_11"}]}$$::jsonb),

-- ── D5: Student Behavior ──────────────────────────────────────────────────────
('india-001', 5, 'The Compliant High-Achiever: Surface Diligence and Hidden Anxiety', 'fully_sourced',
  $${"summary":"Indian students in international classrooms often present as diligent, attentive, and eager to please — which leads many foreign teachers to underestimate the degree of academic anxiety operating underneath. The behaviors that look like engagement are sometimes optimized for teacher approval rather than learning, and the behaviors that look like passivity or reluctance are sometimes learned responses from a system that punished the wrong answer more severely than it rewarded intellectual risk. Understanding this prevents the two most common teacher errors: overestimating readiness for open-ended work, and underestimating the cost of public failure.","sections":[{"heading":"Surface Compliance vs. Deep Understanding","items":["Students trained in structured-answer examinations learn that the correct format is as important as the correct content. Copying notes exactly, asking for model answers, reproducing the teacher's phrasing in written work — these are expert behaviors in CBSE, not signs of intellectual passivity.","When an IB or inquiry task has no single correct answer, students trained in structured formats experience genuine disorientation. The request for 'the right answer' is not intellectual laziness; it is the student trying to identify the game they are now supposed to play.","This creates a specific diagnostic problem for teachers: the student who appears most engaged — taking detailed notes, submitting on time, asking clarifying questions about format — may have the lowest actual conceptual understanding in the class, because they have optimized for visible performance rather than learning.","The correction: differentiate between process evidence (notes, submissions, format compliance) and understanding evidence (application under novel conditions, explanation of reasoning, productive confusion). Indian students often excel on the first and need explicit scaffolding on the second."]},{"heading":"Help-Seeking Avoidance","items":["Asking the teacher a question in front of classmates carries social risk: it reveals that you do not know something, which in a competitive, comparison-saturated peer culture is a meaningful status loss.","Students from competitive family environments have often been taught — explicitly or implicitly — that showing confusion is weakness and that strong students figure things out independently.","Verma, Sharma & Larson (2002) document that Indian secondary students significantly under-report confusion to teachers relative to students in lower-stakes academic contexts. The gap between 'I understand' and actual understanding is systematically larger in high-pressure academic cultures.","Practical response: anonymous question channels (exit tickets, question boxes, shared digital documents), small group check-ins rather than whole-class questioning, and explicit teacher modelling of 'thinking out loud about what I do not yet know' all reduce the social cost of confusion."]},{"heading":"The Pressure-Anxiety-Perfectionism Loop","items":["Academic pressure in Indian middle-class families is unusually concentrated: the child is often carrying the aspirational weight of parents who themselves experienced educational scarcity or constrained opportunity.","Students in this position develop what researchers describe as a perfectionism-anxiety cycle: the fear of failure is so acute that any assessment becomes a high-stakes event, which increases error probability, which confirms the fear.","Assessment format changes are particularly destabilizing: a student who has been producing excellent structured responses and is now asked for creative or exploratory work may show a disproportionate anxiety response, not because the task is harder, but because the predictability of the performance script has been removed.","The most protective intervention is not reassurance ('you'll be fine') but transparency ('here is exactly how this will be assessed, here is an example, here is what success looks like'). Predictability reduces anxiety; vague encouragement amplifies it."]}],"citations":[{"author":"Verma, S., Sharma, D., & Larson, R. W.","year":2002,"title":"School stress in India: Effects on time and daily emotions","journal":"Applied Developmental Science","doi":"10.1207/S1532480XADS0604_11"},{"author":"Bray, M.","year":2009,"title":"Confronting the Shadow Education System","publisher":"UNESCO International Institute for Educational Planning"}]}$$::jsonb),

-- ── D6: Difficult Conversations ───────────────────────────────────────────────
('india-001', 6, 'Five Difficult Conversations — and the Interpretive Move That Changes Each One', 'partial',
  $${"summary":"Five recurring teacher-parent-student flash points in international schools with significant Indian student populations. Each one is frequently misread as an attitude problem, an unreasonable demand, or a cultural incompatibility. In each case, a single interpretive shift changes the teacher's response — and the outcome.","sections":[{"heading":"Flash Point 1: 'What Does 5/7 Mean in Marks?'","items":["The parent or student is asking the question literally: they want to know what 5 out of 7 represents as a percentage, because percentage is the only grading unit they have ever used to compare academic performance.","The common teacher mistake: explaining the IB scale as if the parent's confusion is about scale rather than about meaning. Showing that 5 = 72% does not help; it just recreates the problem in percentage form.","The interpretive move: respond to the underlying question, which is 'Is my child doing well enough?'. Answer that question directly with evidence (what a score of 5 represents in terms of university recognition, what it means in terms of preparation for the next unit), and the marks question resolves itself.","What not to say: 'IB doesn't really work in percentages.' This is technically true and practically useless. It shuts the conversation down without answering the question."]},{"heading":"Flash Point 2: 'My Child Is Doing JEE Coaching — Can You Help?'","items":["This is rarely a request to compromise your academic standards. The parent is asking whether the school and coaching system can co-exist without fragmenting the student's learning.","The common teacher mistake: treating this as a values conflict ('we do inquiry here, not rote preparation') and giving a response that implicitly criticises the family's decision to pursue coaching.","The interpretive move: acknowledge that coaching and IB/AP serve different purposes and that both can co-exist — then ask what the student is finding difficult in the crossover. This is a curriculum conversation, not a beliefs contest.","The concrete offer: 'Tell me which topics the coaching center is covering this term and I'll flag where they connect to what we're doing. That way your child isn't managing two separate systems mentally.'"]},{"heading":"Flash Point 3: 'Why Don't You Give More Notes and Practice Papers?'","items":["In CBSE culture, detailed notes and practice papers are the teacher's primary instructional deliverable. A teacher who does not provide these appears to be withholding help — not offering a pedagogically different approach.","The common teacher mistake: explaining that IB doesn't require notes in that form, or that inquiry-based learning is better for deep understanding. This sounds, from the parent's position, like a refusal to do the job.","The interpretive move: explain what your assessment model actually requires of students, and show what the equivalent preparation looks like in your context. If notes are replaced by graphic organisers, show the graphic organiser and explain its function. If practice papers are replaced by practice tasks, share one.","The goal: make the parent feel that preparation for assessments is structured and supported, even if the structure is different from what they know."]},{"heading":"Flash Point 4: 'My Child Wasn't Ranked — Why Not?'","items":["Public rank-ordering of students by marks is expected in many Indian school contexts. Absence of ranking is interpreted by families as absence of rigorous comparative assessment — not as a deliberate pedagogical choice.","The common teacher mistake: explaining that ranking creates harmful comparison culture and damages self-esteem. This is true and pedagogically sound, but it reads to many Indian parents as the school being evasive about whether their child is competing effectively.","The interpretive move: provide the data you do have. If you track growth over time, show it. If you track performance against the rubric, walk through it. If you can honestly say where the student is performing relative to the expectations for university entry, say it.","The parent is not asking to embarrass other students. They are asking whether their investment is working and whether their child is on track. Giving a specific, honest answer to that question — with data — addresses the underlying concern without requiring a rank."]},{"heading":"Flash Point 5: 'Is This School Recognised for Indian University Admissions?'","items":["This is one of the most practically important questions a parent can ask, and it deserves a specific and honest answer rather than a general reassurance about the school's reputation.","The common teacher mistake: a vague positive response ('absolutely, our students get into excellent universities') that does not actually address the question of board recognition for specific Indian university pathways.","For JEE/NEET: IB is recognized as equivalent to Class 12. AP requires confirmation per institution. IGCSE is recognized as Class 10. The specific subject requirements (PCM for JEE, PCB for NEET) must be met regardless of which board the student is on.","For Indian private universities (Ashoka, FLAME, OP Jindal, Symbiosis, KREA): IB and AP are generally recognised and often attract merit scholarship consideration. The counselor should be able to confirm this with specific university names.","What to say when you do not know: 'I want to give you the right answer, not just a reassuring one. Let me connect you with our university counselor this week.' That is better than a confident-sounding wrong answer."]}],"citations":[{"author":"Bray, M.","year":2009,"title":"Confronting the Shadow Education System","publisher":"UNESCO International Institute for Educational Planning"},{"author":"Kumar, K.","year":1991,"title":"Political Agenda of Education","publisher":"Sage Publications"}]}$$::jsonb)

ON CONFLICT (module_id, dimension_number) DO UPDATE SET
  title           = EXCLUDED.title,
  research_status = EXCLUDED.research_status,
  content         = EXCLUDED.content;

-- ── SCENARIOS ─────────────────────────────────────────────────────────────────

INSERT INTO pd_scenarios (module_id, title, setup, common_misread, actual_dynamic, response_framework, dimension_tags, source_type, status)
VALUES

  ('india-001', 'The Score Comparison',
   'A parent messages you after returning IGCSE mock results. Her daughter received a 6 out of 9 in MYP Science. The parent is distressed — her niece at a CBSE school "just scored 91%" and she does not understand why her daughter seems behind. She asks for a meeting.',
   'The student has underperformed and something is wrong academically.',
   'The parent is translating an MYP criterion score through a CBSE percentage lens. A 6 in MYP Science represents strong performance against internationally moderated criteria — it is not a failing grade. The parent''s distress is real but based on a grading-system translation error, not an academic problem. The meeting is an opportunity to recalibrate, not to defend the grade.',
   '["Acknowledge the parent''s concern directly and without minimising it — she is operating from a real reference point","Show the MYP grading scale explicitly: explain what each level represents in terms of performance, not conversion to percentage","Explain that MYP criteria assess specific skills (knowledge, application, analysis) and that 6/9 means her daughter is performing well against those skills","Do not compare the student to classmates — offer instead a clear picture of where the student is strong and what growth looks like from here","If the parent wants a university-readiness frame, explain how MYP performance feeds into DP and then into admissions outcomes — give her a concrete trajectory, not just reassurance"]'::jsonb,
   '{1,6}'::integer[], 'community_submitted', 'live'),

  ('india-001', 'The Coaching Conflict',
   'A Grade 10 student is clearly struggling with your Physics unit. In a one-to-one conversation he reveals that his JEE coaching class has already covered this topic — using a completely different method. He says ''my tutor says your method won''t work in JEE.'' He is applying the coaching method in your assessments and it is producing partial, incomplete answers.',
   'The student is being disloyal or undermining the school''s approach.',
   'The student is navigating a genuine method conflict between two instructional systems he is simultaneously enrolled in. He is not being defiant; he is using the method he trusts most for the outcome he cares about most. The coaching method may be technically correct but may not be addressing the conceptual understanding your assessment is testing. This is a curriculum conversation, not a discipline situation.',
   '["Sit with the student and ask him to show you the coaching method — understand it before evaluating it","Identify specifically what the coaching method does well and where it falls short for your assessment criteria","Explain the gap directly: ''The coaching method gives you the right answer. My assessment is also asking you to explain why it''s right and what happens when the conditions change.''","Do not ask him to choose between methods — show him how they complement each other","Offer to look at one of his coaching practice papers together to identify where school understanding would have made his coaching answers stronger — this creates buy-in rather than conflict"]'::jsonb,
   '{3,5}'::integer[], 'community_submitted', 'live'),

  ('india-001', 'The Note Request',
   'Three days before a unit test, a parent group message asks whether you can send ''complete notes for the chapter.'' Several parents add supportive reactions. One parent follows up privately: ''All the other teachers provide full notes. My son uses coaching notes for other subjects but you haven''t given anything structured. How is he supposed to revise?''',
   'The parents are being demanding and undermining your pedagogical approach.',
   'The parents are operating with a CBSE-shaped understanding of teacher responsibility: providing structured revision materials before assessments is considered a basic professional duty. The absence of notes signals — to them — that you are not doing your job, not that you have a different pedagogical model. The request is also legitimate: students with heavy coaching schedules need efficient revision materials, not an ideology of inquiry.',
   '["Do not respond defensively in the group — send a direct, practical response","Acknowledge the question: ''I hear that structured revision support would be helpful.''","Share what you have prepared: past papers with model answers, the assessment rubric with annotated examples, a revision guide framed around the key questions the test will ask","Explain briefly what your revision materials are designed to do — not to defend your approach, but to make it legible","After the test: use the results to have a quiet conversation with the parent about what actually helped their child prepare. Data closes this conversation faster than pedagogy arguments."]'::jsonb,
   '{2,3}'::integer[], 'community_submitted', 'live'),

  ('india-001', 'The Quiet Student',
   'Priya is one of your strongest students on written assessments — she consistently produces detailed, well-structured essays. In class discussion and collaborative tasks, she is almost invisible: she does not volunteer answers, looks uncomfortable when cold-called, and contributes minimally in group work. Her parents have never raised a concern. You are worried she will struggle in IB oral assessments.',
   'Priya lacks confidence and needs to be pushed to participate more.',
   'Priya is exhibiting help-seeking avoidance and public-performance risk management typical of students from high-pressure comparison environments. Her written performance tells you she is not lacking in understanding — she is managing social risk. Cold-calling creates the exact public exposure she is protecting against. Pushing harder using the same technique is likely to increase avoidance rather than resolve it.',
   '["Stop cold-calling Priya in front of the class — this technique specifically increases avoidance for students managing performance anxiety","Move toward low-stakes verbal participation: small groups first, then pairs, then whole class","Create an explicit agreement with her: ''I will not call on you without giving you advance notice. When I do, I''ll tell you the topic the day before.''","For oral assessment preparation: begin with recorded private responses (voice memo) before moving to live practice","Talk to her parents — frame it as ''Priya is doing excellent written work and we want to make sure her oral skills reflect the same understanding.'' Do not frame it as a problem."]'::jsonb,
   '{5,4}'::integer[], 'community_submitted', 'live'),

  ('india-001', 'The Predicted Grade Meeting',
   'Arjun''s parents request an urgent meeting. His Grade 11 IB Physics predicted grade is a 5. His conditional offer from a UK engineering programme requires a 6 in HL Physics. His father says the predicted grade is ''the teacher''s personal opinion'' and asks that it be changed. He is polite but firm: ''Arjun works very hard. A 5 is not reflecting who he is.''',
   'The parent is being unreasonable and does not understand how predicted grades work.',
   'The parent is operating from a CBSE-shaped understanding of marks as the product of visible effort and family advocacy — both of which are legitimate levers in that system. He is not trying to cheat; he is using the tools he has always used. The predicted grade represents the teacher''s honest professional assessment of trajectory toward May exams, not an evaluation of Arjun''s character or effort. The meeting is an opportunity to explain the process and, separately, to identify whether there is a real trajectory issue that can be addressed.',
   '["Begin by acknowledging the stakes directly: ''I understand that this predicted grade has direct implications for Arjun''s UK offer. I take that seriously.''","Explain the prediction process: it is a professional assessment of current trajectory toward May exams, moderated by the IB Coordinator — not a single teacher''s opinion","Do not offer to change the prediction in the meeting — but do commit to a specific review timeline","Turn to the concrete: ask what Arjun''s recent Physics assessments show and whether there is an upward trajectory that would justify a revised prediction","Offer a specific, structured support plan with clear milestones: ''If Arjun achieves X in the next mock, that would give me evidence to revise the prediction before the UCAS deadline.'' This transforms the meeting from a confrontation into a roadmap."]'::jsonb,
   '{1,2,6}'::integer[], 'community_submitted', 'live')

ON CONFLICT (module_id, title) DO UPDATE SET
  setup              = EXCLUDED.setup,
  common_misread     = EXCLUDED.common_misread,
  actual_dynamic     = EXCLUDED.actual_dynamic,
  response_framework = EXCLUDED.response_framework,
  status             = EXCLUDED.status;

-- ── QUIZ QUESTIONS ────────────────────────────────────────────────────────────

INSERT INTO pd_quiz_questions (id, module_id, quiz_type, dimension_number, prompt, options, sort_order)
VALUES

  -- Checkpoint D1
  ('india-d1-q1', 'india-001', 'checkpoint', 1,
   'A student who has top marks from CBSE schooling asks "is this going to be in the exam?" in the first week of your IB class. What is the strongest first interpretation?',
   '[{"id":"a","text":"She is signalling low motivation and needs to be challenged on her attitude.","isCorrect":false,"feedback":"This misses the CBSE framing. In a system designed entirely around terminal examinations, allocating effort by marks value is rational expertise, not a character flaw.","research":["Kumar (1991)"]},{"id":"b","text":"She is a high-performer operating rationally inside the only assessment system she has been trained in.","isCorrect":true,"feedback":"Yes. The interpretive move in this module is to read performance optimization as expertise before reading it as disengagement.","research":["Kumar (1991)","Verma, Sharma & Larson (2002)"]},{"id":"c","text":"She is probably more interested in coaching outcomes than school learning and should be spoken to about priorities.","isCorrect":false,"feedback":"Possible, but not the strongest first reading. The question ''is this in the exam'' is a normal CBSE-trained response, not a sign of misplaced priorities.","research":["Kumar (1991)"]}]'::jsonb,
   1),

  -- Checkpoint D2
  ('india-d2-q1', 'india-001', 'checkpoint', 2,
   'A parent sends you a message at 9 PM asking why marks for last week''s test have not been posted yet. What is the most research-informed first reading?',
   '[{"id":"a","text":"The parent is testing your responsiveness and should receive a firm boundary-setting reply.","isCorrect":false,"feedback":"This treats the message as a behavioural problem rather than an information need. The parent is monitoring an investment and using the only communication tool available.","research":["Sujatha (2014)"]},{"id":"b","text":"The parent is monitoring a high-stakes educational investment through the only real-time information channel available to her.","isCorrect":true,"feedback":"Yes. The 9 PM message is more likely to reflect anxiety than hostility. Understanding the investment calculus makes the response much easier to calibrate.","research":["Verma, Sharma & Larson (2002)","Sujatha (2014)"]},{"id":"c","text":"The parent group is likely coordinating to pressure teachers and this message is probably not individual.","isCorrect":false,"feedback":"Parent group coordination is real, but it is not the strongest starting assumption for a single message. Start with the investment interpretation before assuming collective pressure.","research":["Sujatha (2014)"]}]'::jsonb,
   2),

  -- Checkpoint D3
  ('india-d3-q1', 'india-001', 'checkpoint', 3,
   'A student applies a different method to your Physics problem than the one you taught — and gets the right answer. He says his coaching teacher showed him this. What is the most useful first response?',
   '[{"id":"a","text":"Ask the student to use the school method consistently to avoid confusion between systems.","isCorrect":false,"feedback":"This treats the coaching method as an error rather than as legitimate knowledge. It also misses the real diagnostic question: is the student''s method showing conceptual understanding or procedural recall?","research":["Bray (2009)"]},{"id":"b","text":"Explore what the coaching method does and identify specifically what it adds or misses relative to your assessment criteria.","isCorrect":true,"feedback":"Yes. This is the productive move. Understanding the coaching method first lets you identify the actual learning gap — not just the method gap.","research":["Bray (2009)","Sujatha (2014)"]},{"id":"c","text":"Contact the coaching centre to coordinate approaches so the student is not getting conflicting instruction.","isCorrect":false,"feedback":"Well-intentioned but rarely practical and may make the student feel surveilled. The more direct solution is to work with what the student already knows.","research":["Bray (2009)"]}]'::jsonb,
   3),

  -- Final exam Q1
  ('india-final-q1', 'india-001', 'final_exam', NULL,
   'A parent asks ''what does 5 out of 7 mean in percentage?'' in a PTM. What is the best response?',
   '[{"id":"a","text":"Explain that IB does not work in percentages and that marks are criterion-referenced against international standards.","isCorrect":false,"feedback":"Technically correct but practically unhelpful. The parent''s real question is ''Is my child doing well enough?'' — and this answer does not address it.","research":["Kumar (1991)"]},{"id":"b","text":"Answer the underlying question directly — is the child performing well, what does the score mean for future outcomes, and what would improvement look like — rather than explaining the grading system.","isCorrect":true,"feedback":"Yes. The marks question is proxy for ''is my investment working''. Answering it directly closes the conversation; explaining the grading scale often prolongs it.","research":["Verma, Sharma & Larson (2002)"]},{"id":"c","text":"Offer a percentage conversion (5/7 = approximately 71%) and explain this is a good score.","isCorrect":false,"feedback":"This recreates the comparison problem in percentage form. A 71% is below the parent''s reference point of 90%+, which will open a new concern rather than resolve the existing one.","research":["Kumar (1991)"]}]'::jsonb,
   1),

  -- Final exam Q2
  ('india-final-q2', 'india-001', 'final_exam', NULL,
   'Priya is silent in class discussions but her written work is consistently excellent. What does this module suggest as the most important first step?',
   '[{"id":"a","text":"Cold-call her more frequently to build the habit of participation.","isCorrect":false,"feedback":"Cold-calling specifically increases avoidance in students managing public performance anxiety. It is the technique most likely to deepen the pattern.","research":["Verma, Sharma & Larson (2002)"]},{"id":"b","text":"Stop cold-calling, create lower-stakes verbal structures, and give her advance notice before asking for public contribution.","isCorrect":true,"feedback":"Yes. The goal is to reduce the social cost of visible incomprehension — not to force participation through the same high-stakes channel that is already producing avoidance.","research":["Verma, Sharma & Larson (2002)","Bray (2009)"]},{"id":"c","text":"Refer her to counselling for confidence-building before returning to class participation goals.","isCorrect":false,"feedback":"Not yet. The behavior pattern described is a normal academic risk-management response in high-pressure contexts, not necessarily a clinical confidence issue. Pedagogical adjustment should come first.","research":["Verma, Sharma & Larson (2002)"]}]'::jsonb,
   2),

  -- Final exam Q3
  ('india-final-q3', 'india-001', 'final_exam', NULL,
   'A parent requests that his son''s IB Physics predicted grade be changed from 5 to 6 because the current prediction will cost the student his conditional UK offer. What is the correct first move?',
   '[{"id":"a","text":"Explain firmly that predicted grades cannot be changed under any circumstances.","isCorrect":false,"feedback":"Not accurate. Predicted grades can be revised if there is new evidence of an upward trajectory. The point is that they cannot be changed through advocacy alone.","research":["Kumar (1991)"]},{"id":"b","text":"Acknowledge the stakes, explain the prediction process and what evidence would justify a revision, and offer a structured support plan with a clear milestone timeline.","isCorrect":true,"feedback":"Yes. This is the key move: transform the meeting from a confrontation over the current number into a roadmap toward a revised one. The parent wants a trajectory, not a policy lecture.","research":["Verma, Sharma & Larson (2002)"]},{"id":"c","text":"Agree to review the prediction after next week''s mock without committing to any change.","isCorrect":false,"feedback":"Too vague. The parent is working to a UCAS deadline. A response without a specific milestone and timeline is effectively a delay, which will escalate the pressure.","research":["Kumar (1991)"]}]'::jsonb,
   3)

ON CONFLICT (id) DO UPDATE SET
  prompt  = EXCLUDED.prompt,
  options = EXCLUDED.options;

-- ── ASSIGN TO NLIS RIYADH ─────────────────────────────────────────────────────
INSERT INTO assignments (school_id, user_id, role_target, module_slug, assigned_by, due_date)
SELECT
  s.id, NULL, 'teacher', 'india-ib',
  (SELECT id FROM profiles WHERE role = 'admin' ORDER BY created_at LIMIT 1),
  '2026-06-30'
FROM schools s
WHERE s.domain = 'nlis.edu.sa'
  AND NOT EXISTS (
    SELECT 1 FROM assignments a WHERE a.school_id = s.id AND a.module_slug = 'india-ib'
  );

